package web

import (
	"net/http"
	"net/http/httptest"
	"os"
	"path/filepath"
	"strings"
	"testing"
)

func TestIsSandboxGroup(t *testing.T) {
	tests := []struct {
		canonical string
		want      bool
	}{
		// Hex-suffixed groups (auto-generated by handleCreateGroup) are sandbox.
		{"scott-s-test-2c831140", true},
		{"my-group-abcdef01", true},
		{"a-b-12345678", true},
		{"vegas-programmers-1234567890abcdef", true},

		// Real group names (no hex suffix) are not sandbox.
		{"vegas-programmers", false},
		{"vegas", false},
		{"my-test-group", false},  // "group" is not hex
		{"foo-bar-baz", false},    // "baz" is not hex
		{"a-b-cdef1234", true},    // last "-" suffix is 8 hex chars
		{"hello-world-2026", false}, // "2026" is hex but only 4 chars
		{"", false},                // empty
		{"abcdef01", false},        // 8 hex chars but no hyphen separator — not the suffix pattern
		{"foo", false},             // no hyphen
		{"foo-", false},            // trailing hyphen
		{"foo-g", false},           // single hex char, too short
		{"-abcdef01", true},        // hyphen prefix, 8-char hex suffix
		{"FOO-BAR-DEADBEEF", true}, // uppercase hex
		{"group-1234567z", false},  // contains 'z', not hex
	}
	for _, tt := range tests {
		t.Run(tt.canonical, func(t *testing.T) {
			got := isSandboxGroup(tt.canonical)
			if got != tt.want {
				t.Errorf("isSandboxGroup(%q) = %v, want %v", tt.canonical, got, tt.want)
			}
		})
	}
}

func TestHandlePrivacyAndTerms(t *testing.T) {
	// Write a temporary policy file the server can serve.
	dir := t.TempDir()
	privacyPath := filepath.Join(dir, "PRIVACY.md")
	termsPath := filepath.Join(dir, "TERMS.md")
	if err := os.WriteFile(privacyPath, []byte("# Privacy\n\nWe respect you.\n"), 0o644); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(termsPath, []byte("# Terms\n\nBe kind.\n"), 0o644); err != nil {
		t.Fatal(err)
	}
	t.Setenv("FEDMEETUP_PRIVACY_PATH", privacyPath)
	t.Setenv("FEDMEETUP_TERMS_PATH", termsPath)

	srv, cleanup := newTestServer(t)
	defer cleanup()

	tests := []struct {
		path       string
		wantTitle  string
		wantInBody string
	}{
		{"/privacy", "Privacy Policy", "We respect you."},
		{"/terms", "Terms of Service", "Be kind."},
	}
	for _, tt := range tests {
		t.Run(tt.path, func(t *testing.T) {
			req := httptest.NewRequest("GET", tt.path, nil)
			w := httptest.NewRecorder()
			srv.Routes().ServeHTTP(w, req)
			if w.Code != http.StatusOK {
				t.Fatalf("expected 200, got %d (body: %s)", w.Code, w.Body.String())
			}
			body := w.Body.String()
			if !strings.Contains(body, tt.wantTitle) {
				t.Errorf("body missing title %q", tt.wantTitle)
			}
			if !strings.Contains(body, tt.wantInBody) {
				t.Errorf("body missing content %q", tt.wantInBody)
			}
		})
	}
}

func TestHandlePrivacyMissingFile(t *testing.T) {
	t.Setenv("FEDMEETUP_PRIVACY_PATH", "/nonexistent/PRIVACY.md")
	srv, cleanup := newTestServer(t)
	defer cleanup()

	req := httptest.NewRequest("GET", "/privacy", nil)
	w := httptest.NewRecorder()
	srv.Routes().ServeHTTP(w, req)
	if w.Code != http.StatusOK {
		t.Fatalf("expected 200 even when file missing (graceful fallback), got %d", w.Code)
	}
	body := w.Body.String()
	if !strings.Contains(body, "not found") {
		t.Errorf("expected 'not found' message in body, got: %s", body)
	}
}
